<template><view class="page"><view class="section"><view class="title">提现审核</view><view class="card" v-for="item in data.withdrawals" :key="item.id"><view>用户 {{item.user_id}} · ¥{{yuan(item.amount_cents)}}</view><view class="desc">{{item.method}} · {{item.account_name}} · {{item.destination}}</view><view class="actions"><button size="mini" @click="reviewWithdrawal(item,true)">模拟打款</button><button size="mini" @click="reviewWithdrawal(item,false)">驳回</button></view></view><view class="empty" v-if="!data.withdrawals.length">暂无提现申请</view></view>
<view class="section"><view class="title">合伙人审核</view><view class="card" v-for="item in data.partners" :key="item.id"><view>{{item.business_name}} · {{item.business_type}}</view><view class="desc">用户 {{item.user_id}} · {{item.contact_info}}</view><view class="actions"><button size="mini" @click="reviewPartner(item,true)">通过（10%）</button><button size="mini" @click="reviewPartner(item,false)">驳回</button></view></view><view class="empty" v-if="!data.partners.length">暂无合伙人申请</view></view>
<view class="section"><view class="title">待结算佣金</view><view class="card" v-for="item in data.commissions" :key="item.id"><view>用户 {{item.beneficiary_user_id}} · ¥{{yuan(item.commission_cents)}}</view><view class="desc">{{item.commission_type}}</view><button size="mini" @click="settle(item)">结算到余额</button></view><view class="empty" v-if="!data.commissions.length">暂无待结算佣金</view></view></view></template>
<script setup>
import{ref}from'vue';import{onLoad,onPullDownRefresh}from'@dcloudio/uni-app';import http from '@/http/http.js';const data=ref({withdrawals:[],partners:[],commissions:[]});const yuan=c=>(c/100).toFixed(2);const load=async()=>{try{data.value=await http.getGrowthReviews()}finally{uni.stopPullDownRefresh()}};const reviewWithdrawal=async(i,a)=>{await http.reviewWithdrawal(i.id,a,a?'本地模拟打款完成':'资料不符合要求');load()};const reviewPartner=async(i,a)=>{await http.reviewPartner(i.id,a,1000,a?'审核通过':'审核驳回');load()};const settle=async i=>{await http.settleCommission(i.id);load()};onLoad(load);onPullDownRefresh(load);
</script><style scoped>.page{min-height:100vh;padding:26rpx;background:#f3f5f8}.section{margin-bottom:24rpx;padding:26rpx;border-radius:18rpx;background:#fff}.title{font-size:31rpx;font-weight:700}.card{margin-top:18rpx;padding:20rpx;border-radius:12rpx;background:#f8fafc}.desc{margin-top:8rpx;color:#64748b;font-size:22rpx}.actions{display:flex;margin-top:14rpx;gap:12rpx}.actions button{flex:1}.empty{padding:40rpx;text-align:center;color:#94a3b8}</style>
